import pandas as pd
import numpy as np
from typing import Dict, List, Tuple

def create_experimental_conditions() -> Dict[int, Dict]:
    """Generate standardized experimental conditions for T-cell exhaustion experiments."""

    # Define standard components for all conditions
    standard_components = {
        "stimulus_type": "soluble",
        "duration_days": 5,
        "cell_density": 1e5,
        "medium_volume": "100 µL/well (96-well plate)"
    }

    # Condition 1: Conventional T-cell activation (CD3/CD28 + IL-2)
    results[1] = {
        'title': 'Conventional T-cell Activation (CD3/CD28 + IL-2)',
        'details': {
            'model': 'Naïve T-cells',
            'activation_signals': {
                'CD3/CD28': {
                    'type': 'anti-CD3 (OKT3) + anti-CD28 (clone 15E8)',
                    'concentration': '5 µg/mL + 2.5 µg/mL',
                    'format': 'monoclonal antibodies'
                },
                'IL-2': {
                    'source': 'recombinant human IL-2',
                    'concentration': '50 IU/mL',
                    'form': 'soluble cytokine'
                },
                'additional': ['PHA (1 µg/mL)']
            },
            'exhaustion_condition': None,
            'stress_inducers': None,
            'standard_components': standard_components.copy()
        }
    }

    # Condition 2: Secretory T-cell activation (TCR + IL-7 + TGF-β)
    results[2] = {
        'title': 'Secretory T-cell Activation (TCR + IL-7 + TGF-β)',
        'details': {
            'model': 'Naïve T-cells',
            'activation_signals': {
                'TCR': {
                    'type': 'anti-CD3 (clone SP34-2)',
                    'concentration': '10 µg/mL',
                    'format': 'monoclonal antibody'
                },
                'IL-7': {
                    'source': 'recombinant human IL-7',
                    'concentration': '10 ng/mL',
                    'form': 'soluble cytokine'
                },
                'TGF-β': {
                    'source': 'recombinant human TGF-β1',
                    'concentration': '1 ng/mL',
                    'form': 'soluble cytokine'
                },
                'additional': None
            },
            'exhaustion_condition': None,
            'stress_inducers': None,
            'standard_components': standard_components.copy()
        }
    }

    # Condition 3: T-cell exhaustion (deactivation + stress)
    results[3] = {
        'title': 'T-cell Exhaustion (Deactivation + Stress)',
        'details': {
            'model': 'Activated T-cells (from conditions 1 or 2)',
            'activation_signals': {
                'anti-CD3': {
                    'type': 'anti-CD3 (OKT3)',
                    'concentration': '5 µg/mL',
                    'format': 'monoclonal antibody',
                    'exhaustion_mode': 'blockade'
                },
                'anti-CD28': {
                    'type': 'anti-CD28 (clone 15E8)',
                    'concentration': '2.5 µg/mL',
                    'format': 'monoclonal antibody',
                    'exhaustion_mode': 'blockade'
                },
                'IL-2_inhibitor': {
                    'type': 'IL-2 neutralizing antibody',
                    'concentration': '10 µg/mL',
                    'format': 'monoclonal antibody',
                    'exhaustion_mode': 'neutralization'
                }
            },
            'stress_inducers': {
                'IL-2_deprivation': {
                    'method': 'remove IL-2 source',
                    'stress_level': 'high',
                    'effect': 'prolonged activation blockade'
                },
                'additional_stress': {
                    'type': 'H₂O₂ (30 µM) for 1 hour',
                    'purpose': 'oxidative stress',
                    'frequency': 'daily'
                }
            },
            'exhaustion_condition': {
                'duration': '5 days',
                'stress_intensity': 'moderate-high',
                'exhaustion_score': 'high'
            },
            'standard_components': {
                **standard_components,
                'medium': 'X-VIVO 15 with 1% FBS',
                'supplements': ['anti-CD3/anti-CD28 blocking antibodies']
            }
        }
    }

    # Generate experimental table for documentation
    print("\n=== Standardized Experimental Conditions ===")
    common_params = []
    for k, v in standard_components.items():
        common_params.append(f"{k}: {str(v).replace('µ', 'micro')}")
    print(f"Common parameters across all conditions:\n", "\n".join(common_params))

    print("\nCondition 1 (Conventional Activation):")
    print(f"- CD3/CD28: {results[1]['details']['activation_signals']['CD3/CD28']}")
    print(f"- IL-2: {results[1]['details']['activation_signals']['IL-2']}")
    print(f"- PHA: {results[1]['details']['activation_signals']['additional'][0]}")

    print("\nCondition 2 (Secretory Activation):")
    print(f"- TCR: {results[2]['details']['activation_signals']['TCR']}")
    print(f"- IL-7: {results[2]['details']['activation_signals']['IL-7']}")
    print(f"- TGF-β: {results[2]['details']['activation_signals']['TGF-β']}")

    print("\nCondition 3 (Exhaustion Protocol):")
    print(f"- Anti-CD3/CD28 blockade: {results[3]['details']['activation_signals']['anti-CD3']}")
    print(f"- IL-2 neutralization: {results[3]['details']['activation_signals']['IL-2_inhibitor']}")
    print(f"- Stress factors: {results[3]['details']['stress_inducers']}")

    # Create data frame for experimental design
    experiment_design = {
        'Condition': [
            'Conventional Activation',
            'Secretory Activation',
            'Exhaustion Protocol'
        ],
        'Model': [
            'Naïve T-cells',
            'Naïve T-cells',
            'Activated T-cells'
        ],
        'Stimulus 1': [
            'CD3/CD28',
            'TCR (anti-CD3)',
            'Anti-CD3 blockade'
        ],
        'Stimulus 2': [
            'IL-2',
            'IL-7',
            'Anti-CD28 blockade'
        ],
        'Stimulus 3': [
            'PHA',
            'TGF-β',
            'IL-2 neutralization'
        ],
        'Stress Factor': [
            'None',
            'None',
            'Oxidative stress (H₂O₂) + IL-2 deprivation'
        ],
        'Duration (days)': [
            5, 5, 5
        ]
    }

    df_experiment = pd.DataFrame(experiment_design)
    print("\n=== Experimental Design Table ===")
    print(df_experiment.to_string(index=False))

    return {1: results[1], 2: results[2], 3: results[3]}

exhaustion_experimental_conditions = create_experimental_conditions()
